import boto3
import json
import os

def lambda_handler(event, context):
    sns_client = boto3.client('sns')
    
    # Validate and sanitize input
    if 'message' not in event or 'topic_arn' not in event:
        raise ValueError("Invalid input: 'message' and 'topic_arn' are required.")
    
    message = event['message']
    topic_arn = event['topic_arn']
    
    # Validate topic ARN format
    if not topic_arn.startswith("arn:aws:sns:"):
        raise ValueError("Invalid topic ARN format.")
    
    # Publish message to SNS topic
    try:
        response = sns_client.publish(
            TopicArn=topic_arn,
            Message=json.dumps({'default': message}),
            MessageStructure='json'
        )
    except Exception as e:
        raise Exception(f"Failed to publish message: {str(e)}")
    
    return {
        'statusCode': 200,
        'body': json.dumps('Message published successfully.')
    }